code1:
const int xPin = A0;
const int yPin = A1;
const int zPin = A2;

void setup() {
  Serial.begin(9600);
}

void loop() {
  int x = analogRead(xPin);
  int y = analogRead(yPin);
  int z = analogRead(zPin);
  Serial.println(x);
}

const int button = 2;

void setup() {
  pinMode(button, INPUT_PULLUP);
  Serial.begin(9600);
}

void loop() {
  if (digitalRead(button) == LOW) {
    Serial.println("Pressed");
  }
}

const int touch = 2;

void setup() {
  pinMode(touch, INPUT);
  Serial.begin(9600);
}

void loop() {
  if (digitalRead(touch) == HIGH) {
    Serial.println("Touched");
  }
}

#include <Wire.h>

void setup() {
  Wire.begin();
