}

#include <SPI.h>

void setup() {
  SPI.begin();
  pinMode(SS, OUTPUT);
}

void loop() {
  SPI.beginTransaction(SPISettings(4000000, MSBFIRST, SPI_MODE0));
  digitalWrite(SS, LOW);
  SPI.transfer(0x42);
  digitalWrite(SS, HIGH);
  SPI.endTransaction();
}

