void setup() {
  Serial.begin(9600);
}

void loop() {
  Serial.println("Hello");
  if (Serial.available()) {
    char c = Serial.read();
    Serial.println(c);
  }
}

const int trig = 9;
const int echo = 10;

void setup() {
  pinMode(trig, OUTPUT);
  pinMode(echo, INPUT);
  Serial.begin(9600);
}

void loop() {
  digitalWrite(trig, LOW);
  delayMicroseconds(2);
  digitalWrite(trig, HIGH);
  delayMicroseconds(10);
  digitalWrite(trig, LOW);
  long us = pulseIn(echo, HIGH);
  float cm = us * 0.0343 / 2;
  Serial.println(cm);
}

