basic.forever(function () {
    if (input.buttonIsPressed(Button.A)) {
        pins.digitalWritePin(DigitalPin.P0, 1)
    } else {
        pins.digitalWritePin(DigitalPin.P0, 0)
    }

    if (pins.analogReadPin(AnalogPin.P1) > 600) {
        basic.showIcon(IconNames.Yes)
    }
})

